// Flutter with Riverpod
class HomeViewModel extends StateNotifier<HomeState> {
  final GetProductsUseCase _getProducts;
  HomeViewModel(this._getProducts) : super(HomeState.initial());

  Future<void> loadProducts() async {
    state = state.copyWith(isLoading: true);
    final result = await _getProducts();
    result.fold(
      (failure) => state = state.copyWith(error: failure.message),
      (products) => state = state.copyWith(products: products, isLoading: false),
    );
  }
}

class CartBloc extends Bloc<CartEvent, CartState> {
  final CartRepository _repository;
  CartBloc(this._repository) : super(CartInitial()) {
    on<AddToCart>(_onAddToCart);
    on<RemoveFromCart>(_onRemoveFromCart);
  }

  Future<void> _onAddToCart(AddToCart event, Emitter<CartState> emit) async {
    emit(CartLoading());
    try {
      final cart = await _repository.addItem(event.product);
      emit(CartLoaded(cart));
    } catch (e) {
      emit(CartError(e.toString()));
    }
  }
}

// Domain Layer - Use Case
abstract class UseCase<Type, Params> {
  Future<Either<Failure, Type>> call(Params params);
}

class GetUserProfile extends UseCase<User, String> {
  final UserRepository repository;
  GetUserProfile(this.repository);

  @override
  Future<Either<Failure, User>> call(String userId) {
    return repository.getUserById(userId);
  }
}

abstract class UserRepository {
  Future<Either<Failure, User>> getUserById(String id);
  Future<Either<Failure, List<User>>> getUsers();
}

class UserRepositoryImpl implements UserRepository {
  final UserRemoteDataSource remote;
  final UserLocalDataSource local;
  final NetworkInfo networkInfo;

  @override
  Future<Either<Failure, User>> getUserById(String id) async {
    if (await networkInfo.isConnected) {
      final user = await remote.getUser(id);
      await local.cacheUser(user);
      return Right(user);
    } else {
      return Right(await local.getCachedUser(id));
    }
  }
}

// Android MVP
interface HomeView {
    fun showProducts(products: List<Product>)
    fun showError(message: String)
    fun showLoading()
}

class HomePresenter(private val repository: ProductRepository) {
    private var view: HomeView? = null
    fun attachView(v: HomeView) { view = v }
    fun loadProducts() {
        view?.showLoading()
        repository.getProducts { result ->
            result.onSuccess { view?.showProducts(it) }
            result.onFailure { view?.showError(it.message ?: \") }
        }
    }
}"

// Kotlin MVI
data class HomeState(
    val isLoading: Boolean = false,
    val products: List<Product> = emptyList(),
    val error: String? = null
)

sealed class HomeIntent {
    object LoadProducts : HomeIntent()
    data class SearchProducts(val query: String) : HomeIntent()
}

class HomeViewModel : ViewModel() {
    private val _state = MutableStateFlow(HomeState())
    val state: StateFlow<HomeState> = _state.asStateFlow()

    fun processIntent(intent: HomeIntent) {
        when (intent) {
            is HomeIntent.LoadProducts -> loadProducts()
            is HomeIntent.SearchProducts -> search(intent.query)
        }
    }
}

