// Kotlin StateFlow
class ChatViewModel(private val chatRepo: ChatRepository) : ViewModel() {
    private val _messages = MutableStateFlow<List<Message>>(emptyList())
    val messages: StateFlow<List<Message>> = _messages.asStateFlow()

    init {
        viewModelScope.launch {
            chatRepo.observeMessages().collect { msgs ->
                _messages.value = msgs
            }
        }
    }
}

// In Compose
@Composable
fun ChatScreen(viewModel: ChatViewModel) {
    val messages by viewModel.messages.collectAsStateWithLifecycle()
    LazyColumn { items(messages) { MessageItem(it) } }
}

// Model Mapper
class UserMapper {
  static User fromDto(UserDto dto) {
    return User(
      id: dto.id,
      name: '${dto.firstName} ${dto.lastName}',
      email: dto.email,
      avatar: dto.profileImageUrl ?? '',
      joinedAt: DateTime.parse(dto.createdAt),
    );
  }

  static UserDto toDto(User user) {
    final names = user.name.split(' ');
    return UserDto(
      id: user.id,
      firstName: names.first,
      lastName: names.length > 1 ? names.sublist(1).join(' ') : '',
      email: user.email,
    );
  }
}

// Platform-Adaptive Widget Factory
abstract class PlatformWidget {
