  Widget build();
}

// Or using Dart factory constructor
class DialogFactory {
  static Widget create(DialogType type) {
    return switch (type) {
      DialogType.alert => const AlertDialogWidget(),
      DialogType.confirm => const ConfirmDialogWidget(),
      DialogType.input => const InputDialogWidget(),
    };
  }
}

