// Auth Strategy
abstract class AuthStrategy {
  Future<AuthResult> authenticate();
}

class BiometricAuth implements AuthStrategy {
  @override
  Future<AuthResult> authenticate() async {
    final localAuth = LocalAuthentication();
    final success = await localAuth.authenticate(localizedReason: 'Verify identity');
    return success ? AuthResult.success() : AuthResult.failure('Biometric failed');
  }
}

class PinAuth implements AuthStrategy {
  final String expectedPin;
  PinAuth(this.expectedPin);
  @override
  Future<AuthResult> authenticate() async { ... }
}

// Caching Decorator
class CachedProductRepository implements ProductRepository {
  final ProductRepository _inner;
  final CacheService _cache;

  CachedProductRepository(this._inner, this._cache);

  @override
  Future<List<Product>> getProducts() async {
    final cached = await _cache.get<List<Product>>('products');
    if (cached != null) return cached;

    final products = await _inner.getProducts();
    await _cache.set('products', products, ttl: Duration(minutes: 5));
    return products;
  }
}

class DrawCommand {
  final Canvas canvas;
  final Offset start;
  final Offset end;
  final Paint paint;

  DrawCommand({required this.canvas, required this.start, required this.end, required this.paint});

  void execute() => canvas.drawLine(start, end, paint);
  void undo() => canvas.restore();
}

class CommandManager {
  final List<DrawCommand> _history = [];
  int _currentIndex = -1;

  void execute(DrawCommand cmd) {
    cmd.execute();
    _history.add(cmd);
    _currentIndex++;
  }
  void undo() { if (_currentIndex >= 0) _history[_currentIndex--].undo(); }
}

// Dio Interceptor
class AuthInterceptor extends Interceptor {
  final TokenStorage _tokenStorage;

  @override
  void onRequest(RequestOptions options, RequestInterceptorHandler handler) async {
    final token = await _tokenStorage.getAccessToken();
    if (token != null) {
      options.headers['Authorization'] = 'Bearer $token';
    }
    handler.next(options);
  }

  @override
  void onError(DioException err, ErrorInterceptorHandler handler) async {
    if (err.response?.statusCode == 401) {
      final newToken = await _refreshToken();
      // Retry with new token
    }
    handler.next(err);
  }
}

// Freezed State
@freezed
class AuthState with _$AuthState {
  const factory AuthState.initial() = _Initial;
  const factory AuthState.loading() = _Loading;
  const factory AuthState.authenticated(User user) = _Authenticated;
  const factory AuthState.unauthenticated() = _Unauthenticated;
  const factory AuthState.error(String message) = _Error;
}

// Usage with pattern matching
Widget build(BuildContext context) {
  return state.when(
    initial: () => const SplashScreen(),
    loading: () => const LoadingIndicator(),
    authenticated: (user) => HomeScreen(user: user),
    unauthenticated: () => const LoginScreen(),
    error: (msg) => ErrorScreen(message: msg),
  );
}

// Design System Button
class AppButton extends StatelessWidget {
  final String text;
  final VoidCallback onPressed;
  final AppButtonStyle style;
  final bool isLoading;

  const AppButton({required this.text, required this.onPressed, this.style = AppButtonStyle.primary, this.isLoading = false});

  @override
  Widget build(BuildContext context) {
    return ElevatedButton(
      onPressed: isLoading ? null : onPressed,
      style: _getButtonStyle(style),
      child: isLoading
        ? const SizedBox(width: 20, height: 20, child: CircularProgressIndicator(strokeWidth: 2))
        : Text(text),
    );
  }
}

// Use Case
class PlaceOrderUseCase {
  final OrderRepository _orderRepo;
  final InventoryService _inventory;
  final PaymentService _payment;

  PlaceOrderUseCase(this._orderRepo, this._inventory, this._payment);

  Future<Either<Failure, Order>> call(PlaceOrderParams params) async {
    final available = await _inventory.checkAvailability(params.items);
    if (!available) return Left(InsufficientStockFailure());

    final paymentResult = await _payment.charge(params.paymentMethod, params.total);
    if (paymentResult.isLeft()) return paymentResult.map((_) => throw UnimplementedError());

    return _orderRepo.createOrder(params.toOrder());
  }
}

// Swift VIPER
protocol HomeViewProtocol: AnyObject {
    func showProducts(_ products: [ProductViewModel])
    func showError(_ message: String)
}

class HomePresenter {
    weak var view: HomeViewProtocol?
    var interactor: HomeInteractorProtocol?
    var router: HomeRouterProtocol?

    func viewDidLoad() {
        interactor?.fetchProducts()
    }
}

extension HomePresenter: HomeInteractorOutputProtocol {
    func didFetch(products: [Product]) {
        let viewModels = products.map { ProductViewModel(from: $0) }
        view?.showProducts(viewModels)
    }
}

// Redux in React Native
const cartReducer = (state = initialState, action) => {
  switch (action.type) {
    case 'ADD_TO_CART':
      return { ...state, items: [...state.items, action.payload] };
    case 'REMOVE_FROM_CART':
      return { ...state, items: state.items.filter(i => i.id !== action.payload.id) };
    case 'CLEAR_CART':
      return { ...state, items: [] };
    default:
      return state;
  }
};

