// Request Builder
class ApiRequestBuilder {
  String _path = '';
  String _method = 'GET';
  Map<String, String> _headers = {};
  Map<String, dynamic> _queryParams = {};
  dynamic _body;

  ApiRequestBuilder path(String p) { _path = p; return this; }
  ApiRequestBuilder method(String m) { _method = m; return this; }
  ApiRequestBuilder header(String key, String val) { _headers[key] = val; return this; }
  ApiRequestBuilder query(String key, dynamic val) { _queryParams[key] = val; return this; }
  ApiRequestBuilder body(dynamic b) { _body = b; return this; }

  ApiRequest build() => ApiRequest(_path, _method, _headers, _queryParams, _body);
}

// Injectable + GetIt
@injectable
class AuthBloc extends Bloc<AuthEvent, AuthState> {
  final LoginUseCase _loginUseCase;
  final LogoutUseCase _logoutUseCase;

  AuthBloc(this._loginUseCase, this._logoutUseCase) : super(AuthInitial()) {
    on<LoginRequested>((event, emit) async {
      emit(AuthLoading());
      final result = await _loginUseCase(LoginParams(event.email, event.password));
      result.fold(
        (failure) => emit(AuthError(failure.message)),
        (user) => emit(AuthAuthenticated(user)),
      );
    });
  }
}

// Simple Event Bus
class EventBus {
  static final _instance = EventBus._();
  factory EventBus() => _instance;
  EventBus._();

  final _controller = StreamController.broadcast();

  void fire(AppEvent event) => _controller.add(event);
  Stream<T> on<T extends AppEvent>() => _controller.stream.whereType<T>();
  void dispose() => _controller.close();
}

// Usage
EventBus().fire(CartUpdatedEvent(itemCount: 3));
EventBus().on<CartUpdatedEvent>().listen((e) => updateBadge(e.itemCount));

class PaginatedListBloc<T> extends Cubit<PaginatedState<T>> {
  final Future<PaginatedResponse<T>> Function(int page) _fetcher;
  int _currentPage = 1;
  bool _hasMore = true;

  PaginatedListBloc(this._fetcher) : super(PaginatedState.initial());

  Future<void> loadNextPage() async {
    if (!_hasMore || state.isLoadingMore) return;
    emit(state.copyWith(isLoadingMore: true));

    final response = await _fetcher(_currentPage);
    _hasMore = response.hasMore;
    _currentPage++;

    emit(state.copyWith(
      items: [...state.items, ...response.items],
      isLoadingMore: false,
      hasMore: _hasMore,
    ));
  }
}
